const data = $input.first().json;

const counter = String(data.id).padStart(4, '0');

const cleanName = data.project_name
  .toUpperCase()
  .replace(/\s+/g, '_')
  .replace(/[^A-Z0-9_]/g, '');

const poles = typeof data.pole === "string"
  ? JSON.parse(data.pole)
  : data.pole;

const isMultiPole = Array.isArray(poles) && poles.length > 1;

// Mapping nom pôle -> code
const poleCodeMap = {
  "Pôle Tech": "dev",
  "Pôle juridique": "jur",
  "Pôle consultance": "cons",
  "Pôle communication": "com",
  "EGov": "egov",
  "Pôle Bizdev": "bizdev",
  "Pôle RP": "rp",
};
// Code du pôle
const poleCode = isMultiPole
  ? "multi"
  : (poleCodeMap[poles[0]] || "unknown");

// Nom dossier
const folder_name = `${poleCode.toUpperCase()}-PRJ${counter}-${cleanName}`;

const emplacement = isMultiPole
  ? "MULTI_POLE"
  : poleCode.toUpperCase();



return [{
  json: {
    ...data,
    emplacement,
    is_multi_pole: isMultiPole,
    folder_name
  }
}];

