const payloadString = $input.item.json.body.payload;
const payload = JSON.parse(payloadString);

const type = payload.type;

// GESTION BOUTONS

if (type === "block_actions") {

  const action = payload.actions[0];

  return [{
    type: "block_actions",
    action_id: action.action_id,
    project_id: action.value,
    trigger_id: payload.trigger_id
  }];
}
// GESTION FORMULAIRES

if (type === "view_submission") {

  const callback_id = payload.view.callback_id;

  const state = payload.view.state.values;


// ===== POLES =====
 const poles =
    state.pole_name.value.selected_options || [];

  const results_poles = poles.map(item => ({
    pole_selected: item.text.text,
    pole_selected_value: item.value
  }));


// ===== CONTACTS =====
  let result_contact = [];

  const rawContacts =
    state.contact?.value?.value || "";

  if (rawContacts.trim() !== "") {

    result_contact =
      rawContacts
        .split("\n")
        .map(item => ({
          mail: item.trim()
        }));
  }

  // ===== CLIENTS ====
  const selected =
   state.client_name.value.selected_option.value;

  const newClient =
   state.new_client.value.value || "";

  let finalClient;

  if (selected === "Autre") {
    finalClient = newClient;
  } else {
   finalClient = selected;
   }

  // ===== BUDGET =====

  const montant =
    state.project_budget?.value?.value || "";

 // ====EQUIPE==== 
   const equipe =
    state.equipe_associe.value.selected_options || [];

  const results_equipe = equipe.map(item => ({
    equipe_selected: item.text.text,
    equipe_selected_value: item.value
  }))
// ===== OBJET COMMUN =====

  const commonData = {

    project_name:
      state.project_name.value.value,

    client_name:
     finalClient,

    date_debut:
      state.date_debut.value.selected_date,

    montant,

    description:
      state.description.value.value,

    contacts:
      result_contact,

    poles:
      results_poles,
    equipes : 
      results_equipe
  };


  // ===== RH EDIT =====

  if (callback_id === "rh_edit_form") {

    return [{
      type: "rh_edit_form",

      project_id:
        payload.view.private_metadata,

      ...commonData
    }];
  }




  if (callback_id === "new_project_form") {

    return [{
      type: "new_project_form",
      ...commonData
    }];
  }
}

