parameters.jsCode:
const nom_projet = $input.first().json.project_name
  .toLowerCase()
  .replace(/ /g, "-");

const equipe = JSON.parse($input.first().json.equipes);

return [
  {
    json: {
      nom: nom_projet,
      equipe: equipe 
    }
  }
];

const items = $input.all();

return items.map(item => {
  const data = item.json;

  // Transformer pole: array d'objets -> JSON string array de noms
  const poleNames = (data.pole || []).map(p => p.pole_selected);
  const poleString = JSON.stringify(poleNames);

  // Transformer contacts: array d'objets/mails -> JSON string array
  let contactsString;
  if (Array.isArray(data.contacts)) {
    const mails = data.contacts.map(c => typeof c === 'string' ? c : c.mail).filter(Boolean);
    contactsString = JSON.stringify(mails);
  } else {
    contactsString = data.contacts ?? "[]";
  }

  // Transformer equpe: array d'objets -> JSON string array de noms
  const equipeNames = (data.equipes || []).map(e => e.equipe_selected);
  const equipeString = JSON.stringify(equipeNames);
  return {
    json: {
      project_name: data.project_name,
      Client: data.Client,
      pole: poleString,
      description: data.description,
      montant: data.montant ?? "",
      contacts: contactsString,
      equipes: equipeString,
      date_debut: data.date_debut,
      id: data.id,
    }
  };
});

